body:
This adds `$specify2` and `$specify3` cell types for representing timing information from specify blocks in blackbox and whitebox cells. (This also means blackbox cells are not always empty now. They can contain`$specify[23]` cells.)

Consider this example:

```
module test (
	input EN, CLK,
	input [3:0] D,
	output reg [3:0] Q
);
	always @(posedge CLK)
		if (EN) Q <= D;

	specify
		if (EN) (CLK *> (Q : D)) = (1, 2:3:4);
	endspecify
endmodule
```

Running `./yosys -p 'read_verilog -specify test.v; prep; write_verilog -noattr -noexpr'` will produce the following output:

```
module test(EN, CLK, D, Q);
  wire [3:0] _0_;
  input CLK;
  input [3:0] D;
  input EN;
  output [3:0] Q;
  \$dff  #(
    .CLK_POLARITY(1'h1),
    .WIDTH(32'd4)
  ) _1_ (
    .CLK(CLK),
    .D(_0_),
    .Q(Q)
  );
  \$mux  #(
    .WIDTH(32'd4)
  ) _2_ (
    .A(Q),
    .B(D),
    .S(EN),
    .Y(_0_)
  );
  \$specify3  #(
    .DAT_DST_PEN(1'h0),
    .DAT_DST_POL(1'h0),
    .DST_WIDTH(32'd4),
    .EDGE_EN(1'h0),
    .EDGE_POL(1'h0),
    .FULL(1'h1),
    .SRC_DST_PEN(1'h0),
    .SRC_DST_POL(1'h0),
    .SRC_WIDTH(32'd1),
    .T_FALL_MAX(32'sd4),
    .T_FALL_MIN(32'sd2),
    .T_FALL_TYP(32'sd3),
    .T_RISE_MAX(32'sd1),
    .T_RISE_MIN(32'sd1),
    .T_RISE_TYP(32'sd1)
  ) _3_ (
    .DAT(D),
    .DST(Q),
    .EN(EN),
    .SRC(CLK)
  );
endmodule
```

Alternatively, `yosys -p 'read_verilog -specify test.v; prep; write_verilog -noattr'`:

```
module test(EN, CLK, D, Q);
  wire [3:0] _0_;
  input CLK;
  input [3:0] D;
  input EN;
  output [3:0] Q;
  reg [3:0] Q;
  always @(posedge CLK)
      Q <= _0_;
  assign _0_ = EN ? D : Q;
  specify
    if (EN) (CLK *> (Q : D)) = (1:1:1, 2:3:4);
  endspecify
endmodule
```

